def _normalize_endpoint(path: str) -> str:
    if not path:
        return "/"
    if path == "/metrics":
        return "/metrics"
    p = path
    p = re.sub(r"/\d+(?=/|$)", "/:id", p)
    p = re.sub(r"/[0-9a-fA-F]{8,}(?=/|$)", "/:id", p)
    if len(p) > 200:
        p = p[:200]
    return p

def _request_size_bytes() -> int:
    cl = request.headers.get("Content-Length")
    if cl and cl.isdigit():
        return int(cl)
    try:
        data = request.get_data(cache=False, as_text=False)
        return len(data) if data else 0
    except Exception:
        return 0

def _response_size_bytes(resp) -> int:
    try:
        if resp.calculate_content_length() is not None:
            return int(resp.calculate_content_length())
    except Exception:
        pass
    try:
        data = resp.get_data(as_text=False)
        return len(data) if data else 0
    except Exception:
        return 0

